document.querySelector(".content > form").addEventListener("submit",e=>{async function t(){try{const e=await fetch(`${window.location.origin}/api/push`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({long_url:document.querySelector("#pasted_url").value,expiration:document.querySelector("form .expires").getAttribute("data-selected"),user_key:null})}),t=await e.json();if(!e.ok)throw new Error(t.error||"Bad response");if(!0!==t.success)throw new Error(t.response||"Failed to create paste");document.querySelector(".content").classList.add("shortened"),document.querySelector("#pasted_url").value=`${window.location.origin}/${t.response}`,document.querySelector("#pasted_url").setAttribute("data-value",`${window.location.origin}/${t.response}`),document.querySelector("#pasted_url").setAttribute("readonly","")}catch(e){console.error("Fetch Error:",e.message)}}e.preventDefault(),document.querySelector("body > .content").classList.contains("shortened")||t()});